const body = $input.first().json;
const data = body.data || body;
const key = data.key || {};
const msg = data.message || {};
const fromMe = key.fromMe === true;
const numero = (key.remoteJid||'').replace(/@[sg]\.whatsapp\.net|@g\.us/g,'');
const listResp = msg.listResponseMessage;
const list_id = listResp?.singleSelectReply?.selectedRowId || null;
const texto = list_id ? '' : (msg.conversation || msg.extendedTextMessage?.text || '').trim();
const msg_type = list_id ? 'list' : 'text';
if (fromMe || (!texto && !list_id)) return [{skip:true,numero}];
return [{skip:false,numero,msg_type,list_id,texto}];

const sessao = $('GET — sessao').item.json;
const parsed = $('Code — parse mensagem').item.json;
const { numero, msg_type, list_id, texto } = parsed;
const etapa = sessao.etapa || 'idle';
const recurso_tipo = sessao.recurso_tipo || null;
const recurso_nome = sessao.recurso_nome || null;
const ps = sessao.parametros || {};

const toISO = d => d.toISOString().split('T')[0];
const hoje = new Date();
const ano = hoje.getFullYear();
const mes = hoje.getMonth();

function calcPeriodo(id) {
  switch(id) {
    case 'p_este_mes': return {data_inicio:toISO(new Date(ano,mes,1)),data_fim:toISO(new Date(ano,mes+1,0))};
    case 'p_mes_passado': return {data_inicio:toISO(new Date(ano,mes-1,1)),data_fim:toISO(new Date(ano,mes,0))};
    case 'p_30dias': return {data_inicio:toISO(new Date(hoje-30*864e5)),data_fim:toISO(hoje)};
    case 'p_90dias': return {data_inicio:toISO(new Date(hoje-90*864e5)),data_fim:toISO(hoje)};
    default: return null;
  }
}

function parseData(s) {
  let m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (m) return `${m[3]}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}`;
  m = s.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  return m ? s : null;
}

let action = 'send_menu';
let txt = '';
let call_nome = null;
let call_params = {};
let ns = {etapa:'aguardando_menu',recurso_tipo:null,recurso_nome:null,parametros:{}};

const quer_menu = (etapa==='idle'||texto.toLowerCase()==='menu'||texto==='0') && msg_type==='text';

if (quer_menu || etapa==='idle') {
  action='send_menu';
  ns={etapa:'aguardando_menu',recurso_tipo:null,recurso_nome:null,parametros:{}};
}
else if (etapa==='aguardando_menu' && msg_type==='list') {
  if (list_id==='ajuda') {
    action='send_texto';
    txt='*Nexus — Como usar*\n\n📊 *Relatórios disponíveis:*\n• Pedidos por Vendedor — ranking de vendedores com ticket médio e top 5 produtos\n\nDigite *menu* a qualquer momento para voltar ao início.';
    ns={etapa:'aguardando_menu',recurso_tipo:null,recurso_nome:null,parametros:{}};
  } else if (list_id?.startsWith('rel_')) {
    action='send_periodo';
    ns={etapa:'aguardando_periodo',recurso_tipo:'relatorio',recurso_nome:list_id.slice(4),parametros:{cod_empresa:1}};
  } else {
    action='send_menu';
    ns={etapa:'aguardando_menu',recurso_tipo:null,recurso_nome:null,parametros:{}};
  }
}
else if (etapa==='aguardando_periodo' && msg_type==='list') {
  if (list_id==='p_custom') {
    action='send_texto';
    txt='📅 *Data de início:*\nDigite no formato DD/MM/YYYY\nEx: 01/01/2026';
    ns={etapa:'aguardando_data_inicio',recurso_tipo,recurso_nome,parametros:ps};
  } else {
    const p = calcPeriodo(list_id);
    if (p) {
      action='call_relatorio';
      call_nome=recurso_nome;
      call_params={...ps,...p};
      ns={etapa:'idle',recurso_tipo:null,recurso_nome:null,parametros:{}};
    } else {
      action='send_periodo';
      ns=sessao;
    }
  }
}
else if (etapa==='aguardando_data_inicio' && msg_type==='text') {
  const d = parseData(texto.trim());
  if (!d) {
    action='send_texto';
    txt='❌ Formato inválido. Use DD/MM/YYYY\nEx: 01/01/2026';
    ns=sessao;
  } else {
    action='send_texto';
    txt='📅 *Data de fim:*\nDigite no formato DD/MM/YYYY\nEx: 28/02/2026';
    ns={etapa:'aguardando_data_fim',recurso_tipo,recurso_nome,parametros:{...ps,data_inicio:d}};
  }
}
else if (etapa==='aguardando_data_fim' && msg_type==='text') {
  const d = parseData(texto.trim());
  if (!d) {
    action='send_texto';
    txt='❌ Formato inválido. Use DD/MM/YYYY\nEx: 28/02/2026';
    ns=sessao;
  } else {
    action='call_relatorio';
    call_nome=recurso_nome;
    call_params={...ps,data_fim:d};
    ns={etapa:'idle',recurso_tipo:null,recurso_nome:null,parametros:{}};
  }
}
else {
  action='send_menu';
  ns={etapa:'aguardando_menu',recurso_tipo:null,recurso_nome:null,parametros:{}};
}

return [{
  numero,
  next_action: action,
  mensagem_texto: txt,
  recurso_nome: call_nome,
  recurso_nome_sessao: recurso_nome,
  parametros: call_params,
  novo_estado: ns
}];

const item = $json;
return [{
  number: item.numero,
  title: 'Nexus — Sistema ERP',
  description: 'Selecione um relatório',
  buttonText: 'Ver opções',
  footerText: 'Nexus',
  sections: [
    { title: '📊 Relatórios', rows: [
      { rowId: 'rel_pedidos_por_vendedor', title: 'Pedidos por Vendedor', description: 'Ranking com ticket médio e top 5 produtos' }
    ]},
    { title: '❓ Suporte', rows: [
      { rowId: 'ajuda', title: 'Ajuda', description: 'Como usar o Nexus' }
    ]}
  ]
}];

const item = $json;
const nome_fmt = (item.recurso_nome_sessao||'relatório').replace(/_/g,' ');
const hoje = new Date();
const mes_nome = hoje.toLocaleString('pt-BR',{month:'long'});
const ano = hoje.getFullYear();
const mes = hoje.getMonth();
const toISO = d => d.toISOString().split('T')[0];
const ult_mes = new Date(ano,mes-1,1);
const ult_mes_nome = ult_mes.toLocaleString('pt-BR',{month:'long'});
return [{
  number: item.numero,
  title: `Período — ${nome_fmt}`,
  description: 'Selecione o período de consulta',
  buttonText: 'Selecionar',
  footerText: 'Nexus',
  sections: [
    { title: '⚡ Períodos rápidos', rows: [
      { rowId: 'p_este_mes', title: 'Este mês', description: `${mes_nome}/${ano}` },
      { rowId: 'p_mes_passado', title: 'Mês passado', description: `${ult_mes_nome}/${ano}` },
      { rowId: 'p_30dias', title: 'Últimos 30 dias', description: 'Período corrido' },
      { rowId: 'p_90dias', title: 'Último trimestre', description: 'Últimos 90 dias' }
    ]},
    { title: '🗓️ Personalizado', rows: [
      { rowId: 'p_custom', title: 'Período personalizado', description: 'Digitar datas (DD/MM/YYYY)' }
    ]}
  ]
}];

const src = $('Code — state machine').item.json;
const binData = $input.first().binary?.data;
if (!binData) {
  return [{ _tipo:'texto', numero: src.numero, mensagem: '❌ Erro ao gerar o relatório. Tente novamente ou digite *menu*.' }];
}
const b64 = Buffer.from(binData).toString('base64');
const p = src.parametros || {};
const periodo = (p.data_inicio && p.data_fim) ? `${p.data_inicio} a ${p.data_fim}` : 'período selecionado';
const nome_fmt = (src.recurso_nome||'relatório').replace(/_/g,' ');
return [{ _tipo:'pdf', numero: src.numero, base64: b64, caption: `📊 *${nome_fmt}* — ${periodo}` }];
